/* Gameberry Labs optimized styling */

.section h3 {
  font-weight: bold;
  font-size: 14px;
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 8px;
  color: #1e40af;
}

.experience-item h4 {
  font-weight: bold;
  font-size: 12px;
}

.experience-item .company {
  font-weight: normal;
  font-style: italic;
  color: #666;
}

/* Social gaming themed accents */
ul li {
  margin-bottom: 4px;
  line-height: 1.4;
}

.section {
  margin-bottom: 16px;
}

/* Clean, professional typography for ATS and human scanning */
body {
  font-family: 'Arial', 'Calibri', sans-serif;
  font-size: 11px;
  line-height: 1.3;
  color: #333;
}

/* Highlight key social gaming terms */
.highlight {
  font-weight: 600;
  color: #1e40af;
}
